// This JS payload is sent once per page. It collects a structured snapshot of all interactive elements, headings, and table data. Results accumulate into site-map output.
(async () => {
  const pageUrl = window.location.pathname;

  // 1. Collect navigation structure
  const navLinks = [...document.querySelectorAll('.v-navigation-drawer a[href]')]
    .map(a => ({ text: a.textContent.trim(), href: a.getAttribute('href'), active: a.classList.contains('v-list-item--active') }));

  // 2. Collect page headings
  const headings = [...document.querySelectorAll('main h1, main h2, main h3, .v-toolbar-title')]
    .map(h => ({ level: h.tagName, text: h.textContent.trim() }));

  // 3. Collect all interactive elements with Vuetify label resolution
  function getVuetifyLabel(input) {
    const container = input.closest('.v-input, .v-field, .v-text-field');
    if (!container) return null;
    const label = container.querySelector('.v-label, .v-field-label');
    return label?.textContent.trim() ?? null;
  }

  const inputs = [...document.querySelectorAll('input, textarea, select')]
    .filter(el => el.offsetParent !== null)
    .map(el => ({
      tag: el.tagName, type: el.type, id: el.id,
      placeholder: el.placeholder,
      vuetifyLabel: getVuetifyLabel(el),
      ariaLabel: el.getAttribute('aria-label'),
      value: el.type !== 'password' ? el.value : '[REDACTED]'
    }));

  const buttons = [...document.querySelectorAll('button, a[href]')]
    .filter(el => el.offsetParent !== null && el.textContent.trim())
    .map(el => ({
      tag: el.tagName, text: el.textContent.trim().slice(0, 60),
      ariaLabel: el.getAttribute('aria-label'),
      href: el.href || null,
      disabled: el.disabled
    }))
    .filter((b, i, arr) => arr.findIndex(x => x.text === b.text && x.href === b.href) === i)
    .slice(0, 30);

  // 4. Collect table data (first 5 rows)
  const tables = [...document.querySelectorAll('table')].map(table => ({
    headers: [...table.querySelectorAll('thead th')].map(th => th.textContent.trim()),
    rows: [...table.querySelectorAll('tbody tr')].slice(0, 5).map(tr =>
      [...tr.querySelectorAll('td')].map(td => td.textContent.trim().slice(0, 80))
    )
  }));

  // 5. Probe all visible buttons for hover responses (affordance map)
  const affordanceTargets = [...document.querySelectorAll('button')]
    .filter(el => el.offsetParent !== null && !el.textContent.trim())
    .slice(0, 20);
  const affordances = await Promise.all(affordanceTargets.map(async el => {
    el.dispatchEvent(new MouseEvent('mouseenter', { bubbles: true }));
    await new Promise(r => setTimeout(r, 200));
    const tooltip = document.querySelector('.v-overlay--active[role="tooltip"], [role="tooltip"]:not([style*="display: none"])');
    const tooltipText = tooltip?.textContent.trim();
    el.dispatchEvent(new MouseEvent('mouseleave', { bubbles: true }));
    const rect = el.getBoundingClientRect();
    return { selector: el.className?.slice(0,40), x: Math.round(rect.x), y: Math.round(rect.y), tooltip: tooltipText };
  }));

  return { pageUrl, navLinks, headings, inputs, buttons, tables, affordances: affordances.filter(a => a.tooltip) };
})()
